-- migrate:up
-- =========================
-- SYSTEM-OWNED INTEGRATIONS
-- =========================
--
-- Introduce a first-class ownership model for integration definitions so
-- repo-managed OpenAPI specs can be stored once and shared globally.

CREATE TYPE integration_owner_kind AS ENUM (
    'system',
    'org'
);

COMMENT ON TYPE integration_owner_kind IS
'Ownership scope for an integration definition. system = global definition managed from the repo; org = integration owned inside a specific org.';

GRANT USAGE ON TYPE integration_owner_kind TO application_user;
GRANT USAGE ON TYPE integration_owner_kind TO application_readonly;

ALTER TABLE public.integrations
    ADD COLUMN slug TEXT,
    ADD COLUMN owner_kind integration_owner_kind NOT NULL DEFAULT 'org',
    ALTER COLUMN org_id DROP NOT NULL,
    ALTER COLUMN created_by_user_id DROP NOT NULL;

COMMENT ON COLUMN public.integrations.slug IS
'Stable identifier for repo-managed system integrations. NULL for user-created org integrations.';

COMMENT ON COLUMN public.integrations.org_id IS
'Owning org for org-scoped integrations. NULL for system-owned integrations.';

COMMENT ON COLUMN public.integrations.created_by_user_id IS
'Creator for org-scoped integrations. NULL for system-owned integrations.';

ALTER TABLE public.integrations
    ADD CONSTRAINT integrations_owner_scope_chk CHECK (
        (
            owner_kind = 'org'
            AND org_id IS NOT NULL
            AND created_by_user_id IS NOT NULL
            AND slug IS NULL
        )
        OR
        (
            owner_kind = 'system'
            AND org_id IS NULL
            AND created_by_user_id IS NULL
            AND slug IS NOT NULL
            AND visibility = 'org'
        )
    );

CREATE UNIQUE INDEX integrations_system_slug_idx
    ON public.integrations (slug)
    WHERE owner_kind = 'system';

INSERT INTO public.integrations (slug, owner_kind, visibility, openapi_spec)
VALUES
    ('airtable', 'system'::integration_owner_kind, 'org'::resource_visibility, '{"info": {"title": "Airtable Records & Comments API", "x-logo": {"url": "data:image/svg+xml;base64,"}, "version": "1.0.0", "description": "API for viewing Airtable records and record comments using OAuth2.", "x-bionic-slug": "airtable"}, "paths": {"/meta/bases": {"get": {"summary": "List available bases", "security": [{"oauth2": ["data.bases:read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "properties": {"bases": {"type": "array", "items": {"$ref": "#/components/schemas/Base"}}}}}}, "description": "List of bases"}}, "operationId": "listBases"}}, "/{tableName}/records": {"get": {"summary": "List records", "security": [{"oauth2": ["data.records:read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "properties": {"records": {"type": "array", "items": {"$ref": "#/components/schemas/Record"}}}}}}, "description": "List of records"}}, "parameters": [{"in": "path", "name": "tableName", "schema": {"type": "string"}, "required": true}], "operationId": "listRecords"}}, "/{tableName}/records/{recordId}": {"get": {"summary": "Retrieve a record", "security": [{"oauth2": ["data.records:read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Record"}}}, "description": "Single record retrieved"}}, "parameters": [{"in": "path", "name": "tableName", "schema": {"type": "string"}, "required": true}, {"in": "path", "name": "recordId", "schema": {"type": "string"}, "required": true}], "operationId": "getRecord"}}, "/{tableName}/records/{recordId}/comments": {"get": {"summary": "List comments on a record", "security": [{"oauth2": ["data.recordComments:read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "properties": {"comments": {"type": "array", "items": {"$ref": "#/components/schemas/Comment"}}}}}}, "description": "List of comments"}}, "parameters": [{"in": "path", "name": "tableName", "schema": {"type": "string"}, "required": true}, {"in": "path", "name": "recordId", "schema": {"type": "string"}, "required": true}], "operationId": "listRecordComments"}}}, "openapi": "3.0.3", "servers": [{"url": "https://api.airtable.com/v0", "variables": {"baseId": {"default": "app1234567890", "description": "The ID of the Airtable base"}}}], "security": [{"oauth2": ["data.records:read", "data.recordComments:read", "data.bases:read"]}], "components": {"schemas": {"Base": {"type": "object", "required": ["id", "name"], "properties": {"id": {"type": "string"}, "name": {"type": "string"}, "permissionLevel": {"type": "string"}}}, "Record": {"type": "object", "required": ["id", "fields"], "properties": {"id": {"type": "string"}, "fields": {"type": "object", "additionalProperties": true}, "createdTime": {"type": "string", "format": "date-time"}}}, "Comment": {"type": "object", "required": ["id", "text"], "properties": {"id": {"type": "string"}, "text": {"type": "string"}, "userId": {"type": "string"}, "createdTime": {"type": "string", "format": "date-time"}}}}, "securitySchemes": {"oauth2": {"type": "oauth2", "flows": {"authorizationCode": {"scopes": {"data.records:read": "See the data in records", "schema.bases:read": "See information about bases", "data.recordComments:read": "See comments in records"}, "tokenUrl": "https://airtable.com/oauth2/v1/token", "authorizationUrl": "https://airtable.com/oauth2/v1/authorize"}}}}}}'::jsonb),
    ('apollo', 'system'::integration_owner_kind, 'org'::resource_visibility, '{"info": {"title": "Apollo.io Organization Search via URL", "x-logo": {"url": "data:image/svg+xml;base64,"}, "version": "1.0.1", "description": "Search organizations using Apollo.io via a saved URL from the Apollo UI. This endpoint parses and executes searches from saved Apollo links. ⚠️ Consumes one credit per call.", "x-bionic-slug": "apollo"}, "paths": {"/search_organizations_via_url": {"post": {"summary": "Search organizations via Apollo.io saved URL", "responses": {"200": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/SearchViaURLResponse"}}}, "description": "Search results returned successfully"}, "400": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Bad request – missing or invalid parameters"}, "401": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Unauthorized – API key missing or invalid"}, "404": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Not Found – invalid path or resource"}, "429": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Rate limit exceeded"}, "500": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Internal server error"}}, "description": "Execute an Apollo.io organization search using a full saved search URL from the Apollo UI. This endpoint allows recreating searches from the front-end. Returns a paginated list of matching organizations.", "operationId": "searchOrganizationsViaUrl", "requestBody": {"content": {"application/json": {"schema": {"type": "object", "required": ["url", "page"], "properties": {"url": {"type": "string", "example": "https://app.apollo.io/#/companies?organizationNumEmployeesRanges[]=10001&page=1&sortByField=%5Bnone%5D&sortAscending=false&organizationIds[]=5fcd2cf3ed78c700f9383e4e", "description": "The full Apollo UI saved search URL"}, "page": {"type": "integer", "example": 1}}}, "examples": {"default": {"value": {"url": "https://app.apollo.io/#/companies?organizationNumEmployeesRanges[]=10001&page=1&sortByField=%5Bnone%5D&sortAscending=false&organizationIds[]=5fcd2cf3ed78c700f9383e4e", "page": 1}}}}}, "required": true}}}}, "openapi": "3.0.3", "servers": [{"url": "https://apollo-io-no-cookies-required.p.rapidapi.com"}], "security": [{"ApiKeyAuth": []}, {"RapidAPIHost": []}], "components": {"schemas": {"Error": {"type": "object", "properties": {"message": {"type": "string", "example": "Invalid URL or API key"}}}, "Organization": {"type": "object", "properties": {"id": {"type": "string", "example": "5fcd2cf3ed78c700f9383e4e"}, "name": {"type": "string", "example": "Example Corp"}, "domain": {"type": "string", "example": "example.com"}, "industry": {"type": "string", "example": "Software"}, "linkedin_url": {"type": "string", "example": "https://linkedin.com/company/example-corp"}, "num_employees": {"type": "integer", "example": 12000}}}, "SearchViaURLResponse": {"type": "object", "properties": {"page": {"type": "integer", "example": 1}, "total": {"type": "integer", "example": 123}, "per_page": {"type": "integer", "example": 25}, "organizations": {"type": "array", "items": {"$ref": "#/components/schemas/Organization"}}}}}, "securitySchemes": {"ApiKeyAuth": {"in": "header", "name": "x-rapidapi-key", "type": "apiKey"}, "RapidAPIHost": {"in": "header", "name": "x-rapidapi-host", "type": "apiKey"}}}}'::jsonb),
    ('blockchain', 'system'::integration_owner_kind, 'org'::resource_visibility, '{"info": {"title": "Blockchain Ticker API", "x-logo": {"url": "data:image/svg+xml;base64,ICA8c3ZnIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyIgd2lkdGg9IjEwMCIgaGVpZ2h0PSIxMDAiPgogIDx0ZXh0IHg9IjUwJSIgeT0iNTAlIiBkb21pbmFudC1iYXNlbGluZT0ibWlkZGxlIiB0ZXh0LWFuY2hvcj0ibWlkZGxlIiBmb250LXNpemU9IjQ4IiBmb250LWZhbWlseT0ic2Fucy1zZXJpZiI+CiAgICBCCiAgPC90ZXh0Pgo8L3N2Zz4="}, "version": "1.0.0", "description": "Returns current Bitcoin price in various currencies.", "x-bionic-slug": "blockchain"}, "paths": {"/ticker": {"get": {"summary": "Get Bitcoin prices by currency", "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "additionalProperties": {"$ref": "#/components/schemas/CurrencyInfo"}}}}, "description": "A map of currency codes to price information"}}, "operationId": "getTicker"}}}, "openapi": "3.0.3", "servers": [{"url": "https://blockchain.info", "description": "Main Blockchain API server"}], "components": {"schemas": {"CurrencyInfo": {"type": "object", "required": ["15m", "last", "buy", "sell", "symbol"], "properties": {"15m": {"type": "number", "format": "float"}, "buy": {"type": "number", "format": "float"}, "last": {"type": "number", "format": "float"}, "sell": {"type": "number", "format": "float"}, "symbol": {"type": "string"}}}}, "securitySchemes": {"ApiKeyAuth": {"in": "header", "name": "Authorization", "type": "apiKey", "description": "Use the format `Authorization: Bearer <API_KEY>`"}}}}'::jsonb),
    ('dropbox', 'system'::integration_owner_kind, 'org'::resource_visibility, E'{"info": {"title": "Dropbox API - File & Folder Listing", "x-logo": {"url": "data:image/svg+xml;base64,"}, "version": "1.2.0", "description": "OpenAPI spec including file requests, files/folders listing, and file download endpoints.", "x-bionic-slug": "dropbox"}, "paths": {"/2/files/download": {"post": {"tags": ["files"], "servers": [{"url": "https://content.dropboxapi.com"}], "summary": "Download file contents", "security": [{"OAuth2": ["files.content.read"]}], "responses": {"200": {"content": {"text/plain": {}, "application/octet-stream": {}}, "description": "Raw contents of the specified file returned in the response body."}, "default": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Unexpected error"}}, "parameters": [{"in": "header", "name": "Dropbox-API-Arg", "schema": {"type": "string"}, "example": "{\\"path\\": \\"/Documents/report.txt\\"}", "required": true, "description": "A JSON-encoded object with a ''path'' property specifying the file to download (e.g. {\\"path\\": \\"/my-folder/file.txt\\"})"}], "description": "Download the raw contents of a file (binary or text). Returns file data in the HTTP response body, not JSON.", "operationId": "downloadFile"}}, "/2/files/list_folder": {"post": {"tags": ["files"], "summary": "List contents of a folder", "security": [{"OAuth2": ["files.content.read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/ListFolderResult"}}}, "description": "Folder listing result"}, "default": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Unexpected error"}}, "description": "Returns the contents of a folder. Includes both files and subfolders.", "operationId": "listFilesAndFolders", "requestBody": {"content": {"application/json": {"schema": {"type": "object", "required": ["path"], "properties": {"path": {"type": "string", "description": "Path to the folder. Empty string for root."}, "recursive": {"type": "boolean", "default": false}, "include_deleted": {"type": "boolean", "default": false}, "include_media_info": {"type": "boolean", "default": false}}}, "example": {"path": "", "recursive": false}}}, "required": true}}}, "/2/file_requests/list": {"post": {"tags": ["file_requests"], "summary": "List File Requests", "security": [{"OAuth2": ["file_requests.read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "required": ["file_requests"], "properties": {"file_requests": {"type": "array", "items": {"$ref": "#/components/schemas/FileRequest"}}}}}}, "description": "List of file requests"}, "default": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Unexpected error"}}, "description": "Returns a list of file requests owned by this user.", "operationId": "listFileRequests", "requestBody": {"content": {"application/json": {"schema": {"type": "object", "additionalProperties": false}, "example": {}}}, "required": true, "description": "Empty JSON object"}}}, "/2/files/list_folder/continue": {"post": {"tags": ["files"], "summary": "Continue folder listing", "security": [{"OAuth2": ["files.content.read"]}], "responses": {"200": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/ListFolderResult"}}}, "description": "Next set of folder listing results"}, "default": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Error"}}}, "description": "Unexpected error"}}, "description": "Retrieve more results if the previous response indicated `has_more`.", "operationId": "listFilesAndFoldersContinue", "requestBody": {"content": {"application/json": {"schema": {"type": "object", "required": ["cursor"], "properties": {"cursor": {"type": "string", "description": "Cursor from previous /list_folder call."}}}}}, "required": true}}}}, "openapi": "3.0.3", "servers": [{"url": "https://api.dropboxapi.com"}, {"url": "https://content.dropboxapi.com"}], "security": [{"OAuth2": ["file_requests.read", "files.content.read"]}], "components": {"schemas": {"Entry": {"type": "object", "required": [".tag", "name", "id"], "properties": {"id": {"type": "string"}, ".tag": {"enum": ["file", "folder", "deleted"], "type": "string"}, "name": {"type": "string"}, "path_lower": {"type": "string"}, "path_display": {"type": "string"}}, "description": "A file or folder returned from list_folder."}, "Error": {"type": "object", "properties": {"error": {"type": "object"}, "error_summary": {"type": "string"}}}, "FileRequest": {"type": "object", "required": ["id", "url", "title", "created", "is_open", "file_count"], "properties": {"id": {"type": "string", "description": "The ID of the file request."}, "url": {"type": "string", "format": "uri", "description": "The URL of the file request."}, "title": {"type": "string", "description": "The title of the file request."}, "created": {"type": "string", "format": "date-time", "description": "The time this file request was created."}, "is_open": {"type": "boolean", "description": "Whether or not the file request is currently open."}, "file_count": {"type": "integer", "description": "The number of files uploaded to the file request."}}}, "ListFolderResult": {"type": "object", "required": ["entries", "cursor", "has_more"], "properties": {"cursor": {"type": "string"}, "entries": {"type": "array", "items": {"$ref": "#/components/schemas/Entry"}}, "has_more": {"type": "boolean"}}}}, "securitySchemes": {"OAuth2": {"type": "oauth2", "flows": {"authorizationCode": {"scopes": {"file_requests.read": "Read file requests", "files.content.read": "Read file metadata and content", "file_requests.write": "Create and manage file requests"}, "tokenUrl": "https://api.dropboxapi.com/oauth2/token", "authorizationUrl": "https://www.dropbox.com/oauth2/authorize"}}, "description": "OAuth2 authentication for Dropbox API"}}}}'::j