    ('gcal', 'system'::integration_owner_kind, 'org'::resource_visibility, '{"info": {"title": "Google Calendar API - Create Events", "x-logo": {"url": "data:image/svg+xml;base64,"}, "version": "1.0.0", "description": "Minimal OpenAPI spec for creating events in Google Calendar using OAuth 2.0", "x-bionic-slug": "gcal"}, "paths": {"/calendars/{calendarId}/events": {"post": {"summary": "Create a calendar event", "security": [{"OAuth2": ["https://accounts.google.com/o/oauth2/v2/auth"]}], "responses": {"200": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Event"}}}, "description": "Event successfully created"}}, "parameters": [{"in": "path", "name": "calendarId", "schema": {"type": "string", "example": "primary"}, "required": true, "description": "Calendar identifier, e.g. ''primary''"}], "operationId": "createEvent", "requestBody": {"content": {"application/json": {"schema": {"$ref": "#/components/schemas/Event"}}}, "required": true}}}}, "openapi": "3.0.3", "servers": [{"url": "https://www.googleapis.com/calendar/v3"}], "components": {"schemas": {"Event": {"type": "object", "required": ["summary", "start", "end"], "properties": {"end": {"type": "object", "required": ["dateTime"], "properties": {"dateTime": {"type": "string", "format": "date-time", "example": "2025-06-08T11:00:00-07:00"}, "timeZone": {"type": "string", "example": "America/Los_Angeles"}}}, "start": {"type": "object", "required": ["dateTime"], "properties": {"dateTime": {"type": "string", "format": "date-time", "example": "2025-06-08T10:00:00-07:00"}, "timeZone": {"type": "string", "example": "America/Los_Angeles"}}}, "summary": {"type": "string", "example": "Project Sync"}, "location": {"type": "string", "example": "Zoom"}, "attendees": {"type": "array", "items": {"type": "object", "properties": {"email": {"type": "string", "format": "email", "example": "alice@example.com"}}}}, "description": {"type": "string", "example": "Weekly sync-up meeting"}}}}, "securitySchemes": {"OAu