    ('gdrive', 'system'::integration_owner_kind, 'org'::resource_visibility, E'{"info": {"title": "Google Drive API", "x-logo": {"url": "data:image/svg+xml;base64,"}, "version": "1.0.0", "description": "Interact with Google Drive to list files and track changes. This API lets you search, filter, and monitor files and changes in a user''s or shared drive.", "x-bionic-slug": "gdrive"}, "paths": {"/files": {"get": {"summary": "List files in Google Drive", "security": [{"OAuth2": ["https://www.googleapis.com/auth/drive.readonly"]}], "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "properties": {"kind": {"type": "string"}, "files": {"type": "array", "items": {"type": "object", "properties": {"id": {"type": "string"}, "name": {"type": "string"}, "size": {"type": "string"}, "mimeType": {"type": "string"}, "modifiedTime": {"type": "string", "format": "date-time"}}}}, "nextPageToken": {"type": "string"}, "incompleteSearch": {"type": "boolean"}}}, "example": {"kind": "drive#fileList", "files": [{"id": "1A2B3C4D", "name": "bionic_report.pdf", "size": "123456", "mimeType": "application/pdf", "modifiedTime": "2025-07-08T15:00:00Z"}, {"id": "5E6F7G8H", "name": "bionic_notes.txt", "size": "2345", "mimeType": "text/plain", "modifiedTime": "2025-07-07T10:15:00Z"}], "nextPageToken": "next-page-token-string"}}}, "description": "A list of files matching the query."}}, "parameters": [{"in": "query", "name": "q", "schema": {"type": "string"}, "example": "name contains ''bionic''", "description": "A query string for filtering the file results. Example: `name contains ''bionic''`."}, {"in": "query", "name": "corpora", "schema": {"enum": ["user", "domain", "drive", "allDrives"], "type": "string"}, "example": "user", "description": "Bodies of items to which the query applies. Example: `user`."}, {"in": "query", "name": "driveId", "schema": {"type": "string"}, "description": "ID of the shared drive to search."}, {"in": "query", "name": "includeItemsFromAllDrives", "schema": {"type": "boolean"}, "description": "Whether to include items from both My Drive and shared drives."}, {"in": "query", "name": "orderBy", "schema": {"type": "string"}, "example": "modifiedTime desc", "description": "Comma-separated list of sort keys. Example: `modifiedTime desc`."}, {"in": "query", "name": "pageSize", "schema": {"type": "integer", "maximum": 1000, "minimum": 1}, "example": 50, "description": "Maximum number of files to return per page (1-1000)."}, {"in": "query", "name": "pageToken", "schema": {"type": "string"}, "description": "Token for continuing a previous list request."}, {"in": "query", "name": "spaces", "schema": {"enum": ["drive", "appDataFolder"], "type": "string"}, "example": "drive", "description": "Spaces to query within the corpora. Example: `drive`."}, {"in": "query", "name": "fields", "schema": {"type": "string"}, "example": "files(id,name,mimeType,modifiedTime,size),nextPageToken", "description": "Selector specifying which fields to include in a partial response."}], "description": "Lists files the user has access to. Supports advanced filtering, sorting, and pagination. Use the `q` parameter for powerful search queries (e.g., `name contains ''bionic''`).\\n\\n**Note:** This endpoint lists current files and their metadata, but does **not** provide change history or timestamps of when files were changed. For queries about files changed since a specific date, see the `/changes` endpoint and the workflow below.", "operationId": "files_list"}}, "/changes": {"get": {"summary": "List changes in Google Drive", "security": [{"OAuth2": ["https://www.googleapis.com/auth/drive", "https://www.googleapis.com/auth/drive.appdata", "https://www.googleapis.com/auth/drive.file", "https://www.googleapis.com/auth/drive.meet.readonly", "https://www.googleapis.com/auth/drive.metadata", "https://www.googleapis.com/auth/drive.metadata.readonly", "https://www.googleapis.com/auth/drive.photos.readonly", "https://www.googleapis.com/auth/drive.readonly"]}], "responses": {"200": {"content": {"application/json": {"schema": {"type": "object", "properties": {"kind": {"type": "string", "description": "Resource type."}, "changes": {"type": "array", "items": {"type": "object", "properties": {"file": {"type": "object", "properties": {"id": {"type": "string"}, "name": {"type": "string"}, "mimeType": {"type": "string"}, "modifiedTime": {"type": "string", "format": "date-time"}}, "description": "File resource associated with the change."}, "kind": {"type": "string"}, "time": {"type": "string", "format": "date-time"}, "changeType": {"type": "string"}}}}, "nextPageToken": {"type": "string", "description": "Token for next page of results."}, "newStartPageToken": {"type": "string", "description": "Token for future changes."}}}, "example": {"kind": "drive#changeList", "changes": [{"file": {"id": "fileId123", "name": "Example Document", "mimeType": "application/vnd.google-apps.document", "modifiedTime": "2025-06-15T10:00:00Z"}, "kind": "drive#change", "time": "2025-06-15T10:00:00Z", "changeType": "file"}], "nextPageToken": "token_for_next_page", "newStartPageToken": "token_for_future_changes"}}}, "description": "A list of changes for a user or shared drive. Each change includes the file, the type of change, and the time it occurred. Use this endpoint to list files changed since a specific date (using a valid page token)."}}, "parameters": [{"in": "query", "name": "driveId", "schema": {"type": "string"}, "description": "The shared drive from which changes will be returned. If specified, change IDs will be reflective of the shared drive."}, {"in": "query", "name": "includeCorpusRemovals", "schema": {"type": "boolean"}, "description": "Whether to include file resources that are still accessible even after removal from the list of changes."}, {"in": "query", "name": "includeItemsFromAllDrives", "schema": {"type": "boolean"}, "description": "Whether to include items from both My Drive and shared drives."}, {"in": "query", "na